module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const size = args.size || '72px';
const color = args.color || 'var(--accent-color)';
const people = sections.map((s) => (s || '').trim()).filter(Boolean);
let html = `\n\n<div class="mdp-mod-avatarrow" style="--av-size:${size}; --av-color:${color};">`;
people.forEach((p) => {
  const lines = p.split('\n').map((x) => x.trim());
  const imgLine = lines.shift() || '';
  const name = lines.shift() || '';
  const role = lines.join(' ').trim();
  let avatar;
  const im = imgLine.match(/!\[[^\]]*\]\(([^)]+)\)/);
  if (im) avatar = `<img src="${esc(im[1])}" alt="">`;
  else if (/^https?:|^@|^\/|^data:/.test(imgLine)) avatar = `<img src="${esc(imgLine.replace(/^@/, ''))}" alt="">`;
  else avatar = `<span class="mdp-av-emoji">${imgLine}</span>`;
  html += `<div class="mdp-av-item"><div class="mdp-av-pic">${avatar}</div><div class="mdp-av-name">\n\n${name}\n\n</div>${role ? `<div class="mdp-av-role">${esc(role)}</div>` : ''}</div>`;
});
html += `</div>\n\n`;
return html;
